    """Select a tip key from TIPS using self.tip_weights, deterministically via self.rng.

    Nonpositive or missing weights are treated as 0. If every weight ends up
    being 0 (or invalid), falls back to a uniform choice over TIPS keys.
    """
    tip_keys = list(TIPS.keys())
    weights = []
    for key in tip_keys:
        weight = self.tip_weights.get(key, 1.0)
        if not isinstance(weight, (int, float)) or weight <= 0:
            weight = 0.0
        weights.append(float(weight))

    total_weight = sum(weights)
    if total_weight <= 0:
        return self.rng.choice(tip_keys)

    probabilities = [weight / total_weight for weight in weights]

    threshold = self.rng.random()
    cumulative = 0.0
    for key, probability in zip(tip_keys, probabilities):
        cumulative += probability
        if threshold < cumulative:
            return key

    return tip_keys[-1]

